-- 注意注意******组态v2.0对应主系统v2.4版本，主系统v2.4之前的版本不可用******
-- 注意：不管主系统是哪个版本，以下表结构一定要整合到主系统sql文件里，或者单独在数据库执行
-- 如果主系统是使用v2.4脚本sql执行的，注意不要完全复制该scadav2.0脚本执行，需要把该脚本下面的‘菜单’、‘字典’sql删除，下面已有注释说明
-- 组态表结构

CREATE TABLE "scada"
(
    "id" BIGINT AUTO_INCREMENT NOT NULL,
    "guid" VARCHAR(128),
    "scada_data" CLOB,
    "serial_numbers" VARCHAR(50),
    "device_name" VARCHAR(128),
    "is_main_page" INT,
    "page_name" VARCHAR(20),
    "page_resolution" VARCHAR(20),
    "is_share" INT DEFAULT 0,
    "share_url" CLOB,
    "share_pass" VARCHAR(50),
    "page_image" VARCHAR(2000),
    "tenant_id" BIGINT,
    "tenant_name" VARCHAR(30),
    "create_by" VARCHAR(50),
    "create_time" TIMESTAMP(0) DEFAULT CURRENT_TIMESTAMP() NOT NULL,
    "update_by" VARCHAR(50),
    "update_time" TIMESTAMP(0) DEFAULT CURRENT_TIMESTAMP() NOT NULL,
    "del_flag" TINYINT DEFAULT 0 NOT NULL,
    "remark" VARCHAR(800),
    "type" TINYINT,
    "share_short_url" CLOB,
    NOT CLUSTER PRIMARY KEY("id"));

COMMENT ON TABLE "scada" IS '组态页面';
COMMENT ON COLUMN "scada"."create_by" IS '创建人';
COMMENT ON COLUMN "scada"."create_time" IS '创建时间';
COMMENT ON COLUMN "scada"."del_flag" IS '逻辑删除标识';
COMMENT ON COLUMN "scada"."device_name" IS '设备名称';
COMMENT ON COLUMN "scada"."guid" IS '组态id';
COMMENT ON COLUMN "scada"."id" IS 'id唯一标识';
COMMENT ON COLUMN "scada"."is_main_page" IS '是否主界面';
COMMENT ON COLUMN "scada"."is_share" IS '是否分享';
COMMENT ON COLUMN "scada"."page_image" IS '页面图片';
COMMENT ON COLUMN "scada"."page_name" IS '页面名称';
COMMENT ON COLUMN "scada"."page_resolution" IS '页面大小';
COMMENT ON COLUMN "scada"."remark" IS '备注';
COMMENT ON COLUMN "scada"."scada_data" IS '组态信息';
COMMENT ON COLUMN "scada"."serial_numbers" IS '设备编号';
COMMENT ON COLUMN "scada"."share_pass" IS '分享密码';
COMMENT ON COLUMN "scada"."share_short_url" IS '分享短链接';
COMMENT ON COLUMN "scada"."share_url" IS '分享链接';
COMMENT ON COLUMN "scada"."tenant_id" IS '租户id';
COMMENT ON COLUMN "scada"."tenant_name" IS '租户名称';
COMMENT ON COLUMN "scada"."type" IS '组态类型 1- 模板组态 2- 场景组态 3-公共组态';
COMMENT ON COLUMN "scada"."update_by" IS '更新人';
COMMENT ON COLUMN "scada"."update_time" IS '更新时间';

CREATE TABLE "scada_component"
(
    "id" BIGINT AUTO_INCREMENT NOT NULL,
    "component_name" VARCHAR(20),
    "component_template" CLOB,
    "component_style" CLOB,
    "component_script" CLOB,
    "component_image" VARCHAR(100),
    "tenant_id" BIGINT,
    "tenant_name" VARCHAR(30),
    "create_by" VARCHAR(50),
    "create_time" TIMESTAMP(0) DEFAULT CURRENT_TIMESTAMP() NOT NULL,
    "update_by" VARCHAR(50),
    "update_time" TIMESTAMP(0) DEFAULT CURRENT_TIMESTAMP() NOT NULL,
    "del_flag" TINYINT DEFAULT 0 NOT NULL,
    "is_share" INT DEFAULT 1,
    "user_id" BIGINT,
    NOT CLUSTER PRIMARY KEY("id")) ;

COMMENT ON TABLE "scada_component" IS '组态组件表';
COMMENT ON COLUMN "scada_component"."component_image" IS '组件缩略图';
COMMENT ON COLUMN "scada_component"."component_name" IS '组件名称';
COMMENT ON COLUMN "scada_component"."component_script" IS '组件脚本';
COMMENT ON COLUMN "scada_component"."component_style" IS '组件风格';
COMMENT ON COLUMN "scada_component"."component_template" IS '组件模版';
COMMENT ON COLUMN "scada_component"."create_by" IS '创建人';
COMMENT ON COLUMN "scada_component"."create_time" IS '创建时间';
COMMENT ON COLUMN "scada_component"."del_flag" IS '逻辑删除标识';
COMMENT ON COLUMN "scada_component"."id" IS '主键id';
COMMENT ON COLUMN "scada_component"."is_share" IS '分享类型（0-私有；1-公有）';
COMMENT ON COLUMN "scada_component"."tenant_id" IS '租户id';
COMMENT ON COLUMN "scada_component"."tenant_name" IS '租户名称';
COMMENT ON COLUMN "scada_component"."update_by" IS '更新人';
COMMENT ON COLUMN "scada_component"."update_time" IS '更新时间';
COMMENT ON COLUMN "scada_component"."user_id" IS '用户id';


CREATE TABLE "scada_device_bind"
(
    "id" bigint auto_increment not null,
    "serial_number" varchar(20),
    "scada_guid" varchar(128),
    not cluster primary key("id"));

COMMENT ON TABLE "scada_device_bind" is '组态设备关联表';
COMMENT ON COLUMN "scada_device_bind"."id" is 'id唯一标识';
COMMENT ON COLUMN  "scada_device_bind"."scada_guid" is '组态guid';
COMMENT ON COLUMN "scada_device_bind"."serial_number" is '设备编号';


CREATE TABLE "scada_device_share"
(
    "id" bigint auto_increment not null,
    "guid" varchar(128) not null,
    "serial_number" varchar(20) not null,
    "is_share" int,
    "share_url" clob,
    "share_pass" varchar(200),
    "share_short_url" clob,
    not cluster primary key("id"));

COMMENT ON COLUMN "scada_device_share"."guid" is '组态id';
COMMENT ON COLUMN "scada_device_share"."id" is '主键id';
COMMENT ON COLUMN "scada_device_share"."is_share" is '是否分享';
COMMENT ON COLUMN "scada_device_share"."serial_number" is '设备编号';
COMMENT ON COLUMN "scada_device_share"."share_pass" is '分享密码';
COMMENT ON COLUMN "scada_device_share"."share_short_url" is '分享短链接';
COMMENT ON COLUMN "scada_device_share"."share_url" is '分享链接';


CREATE TABLE "scada_echart"
(
    "id" bigint auto_increment not null,
    "guid" varchar(128),
    "echart_name" varchar(20),
    "echart_type" varchar(10),
    "echart_data" clob,
    "echart_imgae" varchar(255),
    "tenant_id" bigint,
    "tenant_name" varchar(30),
    "create_by" varchar(50),
    "create_time" timestamp(0) default current_timestamp() not null,
    "update_by" varchar(50),
    "update_time" timestamp(0) default current_timestamp() not null,
    "del_flag" tinyint default 0 not null,
    not cluster primary key("id"));

COMMENT ON TABLE "scada_echart" IS '图表管理';
COMMENT ON COLUMN "scada_echart"."create_by" is '创建人';
COMMENT ON COLUMN "scada_echart"."create_time" is '创建时间';
COMMENT ON COLUMN "scada_echart"."del_flag" is '逻辑删除标识';
COMMENT ON COLUMN "scada_echart"."echart_data" is '图表内容';
COMMENT ON COLUMN "scada_echart"."echart_imgae" is '图表图片';
COMMENT ON COLUMN "scada_echart"."echart_name" is '图表名称';
COMMENT ON COLUMN "scada_echart"."echart_type" is '图表类别';
COMMENT ON COLUMN "scada_echart"."id" is 'id';
COMMENT ON COLUMN "scada_echart"."tenant_id" is '租户id';
COMMENT ON COLUMN "scada_echart"."tenant_name" is '租户名称';
COMMENT ON COLUMN "scada_echart"."update_by" is '更新人';
COMMENT ON COLUMN "scada_echart"."update_time" is '更新时间';


CREATE TABLE "scada_gallery"
(
    "id" bigint auto_increment not null,
    "file_name" varchar(255),
    "category_name" varchar(255),
    "resource_url" varchar(512),
    "tenant_id" bigint,
    "tenant_name" varchar(30),
    "create_by" varchar(50),
    "create_time" timestamp(0) default current_timestamp(),
    "update_by" varchar(50),
    "update_time" timestamp(0) default current_timestamp(),
    "del_flag" tinyint default 0,
    not cluster primary key("id"));

COMMENT ON TABLE "scada_gallery" IS '组态图库表';
COMMENT ON COLUMN "scada_gallery"."category_name" is '分类名称';
COMMENT ON COLUMN "scada_gallery"."create_by" is '创建人';
COMMENT ON COLUMN "scada_gallery"."create_time" is '创建时间';
COMMENT ON COLUMN "scada_gallery"."del_flag" is '逻辑删除标识';
COMMENT ON COLUMN "scada_gallery"."file_name" is '文件名称';
COMMENT ON COLUMN "scada_gallery"."id" is 'id唯一标识';
COMMENT ON COLUMN "scada_gallery"."resource_url" is '资源请求路径';
COMMENT ON COLUMN "scada_gallery"."tenant_id" is '租户id';
COMMENT ON COLUMN "scada_gallery"."tenant_name" is '租户名称';
COMMENT ON COLUMN "scada_gallery"."update_by" is '更新人';
COMMENT ON COLUMN "scada_gallery"."update_time" is '更新时间';

CREATE TABLE "scada_model"
(
    "id" bigint auto_increment not null,
    "model_name" varchar(50),
    "model_url" varchar(512),
    "status" int,
    "image_url" varchar(512),
    "tenant_id" bigint,
    "tenant_name" varchar(30),
    "create_by" varchar(50),
    "create_time" timestamp(0) default current_timestamp() not null,
    "update_by" varchar(50),
    "update_time" timestamp(0) default current_timestamp() not null,
    "del_flag" tinyint default 0 not null,
    "model_type" varchar(20),
    not cluster primary key("id"));

COMMENT ON TABLE "scada_model" IS '三维配置表';
COMMENT ON COLUMN "scada_model"."create_by" is '创建人';
COMMENT ON COLUMN "scada_model"."create_time" is '创建时间';
COMMENT ON COLUMN "scada_model"."del_flag" is '逻辑删除标识';
COMMENT ON COLUMN "scada_model"."model_type" is '模型类型';
COMMENT ON COLUMN "scada_model"."image_url" is '缩略图url';
COMMENT ON COLUMN "scada_model"."model_name" is '模型名称';
COMMENT ON COLUMN "scada_model"."model_url" is '模型地址';
COMMENT ON COLUMN "scada_model"."status" is '是否弃用';
COMMENT ON COLUMN "scada_model"."tenant_id" is '租户id';
COMMENT ON COLUMN "scada_model"."tenant_name" is '租户名称';
COMMENT ON COLUMN "scada_model"."update_by" is '更新人';
COMMENT ON COLUMN "scada_model"."update_time" is '更新时间';




ALTER TABLE "scada_gallery"
    ADD COLUMN "sys_flag" TINYINT  NOT NULL DEFAULT 0;
COMMENT ON COLUMN "scada_gallery"."sys_flag" IS '是否系统通用（0-否，1-是）';

update scada_gallery
set SYS_FLAG = 1,
    TENANT_ID = 1;

UPDATE scada_gallery s
SET tenant_name = (SELECT d.dept_name FROM sys_dept d WHERE d.dept_user_id = s.tenant_id),
    create_by = (SELECT su.user_name FROM sys_user su WHERE su.user_id = s.tenant_id)
WHERE EXISTS (SELECT 1 FROM sys_dept d WHERE d.dept_user_id = s.tenant_id);
